hints = typing.get_type_hints(HCGRCState, include_extras=True)
from src.state import initial_state

state = initial_state()

print("=== Verifying initial state completeness ===")
missing = []
for field_name in hints:
    if field_name not in state:
        missing.append(field_name)

if missing:
    print(f"MISSING FIELDS: {missing}")
else:
    print("✓ All fields present in initial state")

# Check for type mismatches
print("\n=== Checking type correctness ===")
issues = []
for field_name, hint in hints.items():
    value = state[field_name]
    hint_str = str(hint)

    # Check list fields
    if 'list' in hint_str:
        if not isinstance(value, list):
            issues.append(f"{field_name}: expected list, got {type(value).__name__}")

    # Check dict fields
    if 'dict' in hint_str and 'gate_status' in field_name:
        if not isinstance(value, dict):
            issues.append(f"{field_name}: expected dict, got {type(value).__name__}")

if issues:
    for issue in issues:
        print(f"  ✗ {issue}")
else:
    print("✓ All field types correct")
EOF

